    private JSONObject getUpdatedApprovalJSON(Workflow wf) {
          JSONObject jo = new JSONObject();

          JSONArray approvalSteps = new JSONArray();
          try {
              jo.put("_approval_steps", approvalSteps);
              if (wf != null) {
                  List<String> nextUsers = wf.getNextUsers();
                  if(nextUsers.size() > 1) {
                      JSONArray nextUserArr = new JSONArray();
                      for(String nextUser:nextUsers) {
                          nextUserArr.put(nextUser);
                      }
                      jo.put("_approve_next", nextUserArr);
                  } else {
                      jo.put("_approve_next", wf.getNextUser());
                  }

                  jo.put("_approve_status", wf.getStatus());
                  jo.put("_approval_id", wf.getWfId());
                  jo.put("_approval_submitter", wf.getSubmitter());

                  for(WorkflowStep ws:wf.getWorkflowHistory()){
                      boolean isMultiStep = ws.getEmails().size() > 1;
                      if(isMultiStep) {
                          JSONObject approvalStep = new JSONObject();
                          JSONArray signerEmails = new JSONArray();
                          JSONArray signerNames = new JSONArray();
                          JSONArray signerSignCondition = new JSONArray();
                          JSONArray signerComments = new JSONArray();
                          JSONArray signerDeputies = new JSONArray();
                          List<String> emails = ws.getEmails();
                          List<String> userNames = ws.getUserNames();
                          for(int i = 0; i < ws.getEmails().size() ;i++) {
                              String email = emails.get(i);
                              signerEmails.put(email);
                              signerNames.put(userNames.get(i));
                              signerSignCondition.put(ws.getUsersSignCondition(wf.getApname(), emails.get(i)));
                              signerDeputies.put(getDeputy(wf.getApname(), email));
                          }

                          Account account = Account.getInstance(wf.getApname());
                          for(Map.Entry<String, String> c: ws.getComments().entrySet()) {
                              String userEmail =  c.getKey();
                              int i = ws.getEmails().indexOf(userEmail);
                              String userName = i > -1 ? ws.getUserNames().get(i): account.getUserName(userEmail);
                              String userComment = c.getValue();
                              JSONObject signerCommentJo = new JSONObject();
                              signerCommentJo.put("userId" , userEmail);
                              signerCommentJo.put("userName" , userName);
                              signerCommentJo.put("comment" , userComment);
                              signerComments.put(signerCommentJo);
                          }

                          approvalStep.put("_signer", signerNames);
                          approvalStep.put("_signer_email", signerEmails);
                          approvalStep.put("_signer_comments", signerComments);
                          approvalStep.put("_signer_condition", signerSignCondition);
                          approvalStep.put("_step_name", ws.getStepName());
                          approvalStep.put("_step_status", ws.getStatus());
                          approvalStep.put("_step_response", ws.getResponse());
                          approvalStep.put("_step_threshold", ws.getThreshold());
                          approvalStep.put("_step_deputies", signerDeputies);
                          approvalSteps.put(approvalStep);
                      } else {
                          JSONObject approvalStep = new JSONObject();
                          approvalStep.put("_signer", ws.getUserName());
                          approvalStep.put("_signer_email", ws.getEmail());
                          approvalStep.put("_signer_comment", ws.getComment());
                          approvalStep.put("_step_name", ws.getStepName());
                          approvalStep.put("_step_status", ws.getStatus());
                          approvalStep.put("_step_response", ws.getResponse());
                          approvalStep.put("_step_deputy", getDeputy(wf.getApname(), ws.getEmail()));
                          approvalSteps.put(approvalStep);
                      }
                  }
              } else {
                  jo.put("_approve_next", "");
                  jo.put("_approve_status", "");
                  jo.put("_approval_id", "");
                  jo.put("_approval_submitter", "");
              }
          } catch (JSONException ignored) { }

          return jo;
    }

